def execute_task_call(self, call: TaskCall, expect_fail: bool) -> Any:
    """Execute a task call."""
    call.parent = self.parent_id
    call.expect_fail = expect_fail

    # Evaluate arguments
    args = [self.evaluate_expr(a) if isinstance(a, ASTNode) else a for a in call.args]
    kwargs = {k: self.evaluate_expr(v) if isinstance(v, ASTNode) else v
              for k, v in call.kwargs.items()}

    call.args = args
    call.kwargs = kwargs

    result = self.executor.execute_task(call)

    if expect_fail:
        # We expected this task to fail
        if result.exit_code == 0:
            raise EvaluationError(f"Task {call.name} was expected to fail but succeeded")
        return True  # Continue execution
    else:
        if result.exit_code != 0:
            raise EvaluationError(f"Task {call.name} failed")
        return True

def evaluate_fails_task(self, stmt: FailsTask) -> Any:
    """Evaluate a fails(task) expression."""
    return self.execute_task_call(stmt.task_call, expect_fail=True)

