                return True
            return self.is_truthy(self.evaluate_expr(expr.right))

        right = self.evaluate_expr(expr.right)

        if expr.op == '+':
            return left + right
        elif expr.op == '-':
            return left - right
        elif expr.op == '*':
            return left * right
        elif expr.op == '/':
            if right == 0:
                raise EvaluationError("Division by zero")
            return left / right
        elif expr.op == '%':
