        elif expr.op == '!=':
            return left != right
        elif expr.op == '<':
            return left < right
        elif expr.op == '>':
            return left > right
        elif expr.op == '<=':
            return left <= right
        elif expr.op == '>=':
            return left >= right
        else:
            raise EvaluationError(f"Unknown operator: {expr.op}")

    def evaluate_unary_op(self, expr: UnaryOp) -> Any:
